arguments.file_text:
@page "/settings"
@using sv_117e8ac5c8464b5aa11d4b2e2f54ec9c.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
</div>

@* ───────── Profile Section ───────── *@

@{ RenderFragment RenderProfile() =>
    @<section class="settings-section">
        <h3>Profile</h3>
        <p class="text-muted">Manage your public profile information.</p>

        <div class="avatar-area mb-4">
            <img src="@_editProfile!.AvatarUrl" alt="Avatar" class="avatar-preview" />
            <span class="text-muted small">@_editProfile.AvatarUrl</span>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_editProfile.DisplayName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_editProfile.Email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    </section>;
}

@* ───────── Notifications Section ───────── *@

@{ RenderFragment RenderNotifications() =>
    @<section class="settings-section">
        <h3>Notifications</h3>
        <p class="text-muted">Choose how you want to be notified.</p>

        <div class="toggle-group mb-4">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive updates via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_editNotifications!.EmailNotifications"
                           @onchange="e => _editNotifications.EmailNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications on your devices</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_editNotifications.PushNotifications"
                           @onchange="e => _editNotifications.PushNotifications = (bool)e.Value!" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_editNotifications.WeeklyDigest"
                           @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                </div>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <div class="channel-list mb-4">
            @foreach (var channel in _editNotifications.AllChannels)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_editNotifications.MutedSet.Contains(channel)"
                           @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
    </section>;
}

@* ───────── Security Section ───────── *@

@{ RenderFragment RenderSecurity() =>
    @<section class="settings-section">
        <h3>Security</h3>
        <p class="text-muted">Manage your account security settings.</p>

        <!-- Change Password -->
        <div class="card mb-4">
            <div class="card-header expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <strong>Change Password</strong>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="text-danger small mb-2">@_passwordError</div>
                    }
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="card mb-4">
            <div class="card-body">
                <div class="toggle-row">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <div class="small">
                            Status:
                            <span class="badge @(_securitySettings!.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                                @(_securitySettings.TwoFactorEnabled ? "Enabled" : "Disabled")
                            </span>
                        </div>
                        @if (_securitySettings.LastPasswordChange.HasValue)
                        {
                            <div class="text-muted small mt-1">
                                Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                            </div>
                        }
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_securitySettings.TwoFactorEnabled"
                               @onchange="ToggleTwoFactor" />
                    </div>
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _securitySettings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevokeSession(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> in
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                            <p class="text-muted small">This will sign out that device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </section>;
}

@* ───────── Appearance Section ───────── *@

