                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_editNotifications.WeeklyDigest"
                           @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                </div>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <div class="channel-list mb-4">
            @foreach (var channel in _editNotifications.AllChannels)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_editNotifications.MutedSet.Contains(channel)"
                           @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
    </section>;
}

@* ───────── Security Section ───────── *@

@{ RenderFragment RenderSecurity() =>
    @<section class="settings-section">
        <h3>Security</h3>
        <p class="text-muted">Manage your account security settings.</p>

        <!-- Change Password -->
        <div class="card mb-4">
            <div class="card-header expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <strong>Change Password</strong>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="text-danger small mb-2">@_passwordError</div>
                    }
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="card mb-4">
            <div class="card-body">
                <div class="toggle-row">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <div class="small">
                            Status:
                            <span class="badge @(_securitySettings!.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                                @(_securitySettings.TwoFactorEnabled ? "Enabled" : "Disabled")
                            </span>
                        </div>
                        @if (_securitySettings.LastPasswordChange.HasValue)
                        {
                            <div class="text-muted small mt-1">
                                Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                            </div>
                        }
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_securitySettings.TwoFactorEnabled"
                               @onchange="ToggleTwoFactor" />
                    </div>
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _securitySettings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevokeSession(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> in
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                            <p class="text-muted small">This will sign out that device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </section>;
}

@* ───────── Appearance Section ───────── *@

@{ RenderFragment RenderAppearance() =>
    @<section class="settings-section">
        <h3>Appearance</h3>
        <p class="text-muted">Customize how the application looks.</p>

        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   checked="@(_editAppearance!.Theme == theme)"
                                   @onchange="() => _editAppearance.Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   checked="@(_editAppearance.FontSize == size)"
                                   @onchange="() => _editAppearance.FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" value="@_editAppearance.Language"
                            @onchange="e => _editAppearance.Language = e.Value!.ToString()!">
                        <option>English</option>
                        <option>Spanish</option>
                        <option>French</option>
                        <option>German</option>
                        <option>Japanese</option>
                        <option>Portuguese</option>
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="toggle-row">
                        <div>
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_editAppearance.CompactMode"
                                   @onchange="e => _editAppearance.CompactMode = (bool)e.Value!" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-6">
                <h5>Preview</h5>
                <div class="appearance-preview @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is a preview of your selected appearance settings.</p>
                        <button class="preview-btn">Sample Button</button>
                        <div class="preview-card">
                            <strong>Card Title</strong>
                            <p>Card content with <a href="#">a link</a> inside.</p>
                        </div>
                    </div>
                    <div class="preview-meta">
                        Theme: @_editAppearance.Theme · Font: @_editAppearance.FontSize ·
                        Lang: @_editAppearance.Language · Compact: @(_editAppearance.CompactMode ? "On" : "Off")
                    </div>
                </div>
            </div>
        </div>
    </section>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Icon, string Label)> _sections = new()
    {
        ["profile"] = ("👤", "Profile"),
        ["notifications"] = ("🔔", "Notifications"),
        ["security"] = ("🔒", "Security"),
        ["appearance"] = ("🎨", "Appearance")
    };

    // ── Loading / Toast ──
    private bool _loading = true;
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile ──
    private ProfileEdit? _editProfile;
    private UserProfile? _savedProfile;

    // ── Notifications ──
    private NotificationsEdit? _editNotifications;

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "sess-1";

    // ── Appearance ──
    private AppearanceEdit? _editAppearance;

    // ────────────────────────── Lifecycle ──────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _savedProfile = profileTask.Result;
        _editProfile = ProfileEdit.From(_savedProfile);

        var notifs = notifTask.Result;
        _editNotifications = NotificationsEdit.From(notifs);

        _securitySettings = securityTask.Result;

        var appearance = appearanceTask.Result;
        _editAppearance = AppearanceEdit.From(appearance);

        _loading = false;
    }

    // ────────────────────────── Profile ──────────────────────────

    private async Task SaveProfile()
    {
        var profile = new UserProfile(
            _editProfile!.DisplayName,
            _editProfile.Email,
            _editProfile.AvatarUrl,
            _editProfile.Bio);

        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        _editProfile = ProfileEdit.From(_savedProfile!);
    }

    // ────────────────────────── Notifications ──────────────────────────

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editNotifications!.MutedSet.Add(channel);
        else
            _editNotifications!.MutedSet.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _editNotifications!.EmailNotifications,
            _editNotifications.PushNotifications,
            _editNotifications.WeeklyDigest,
            _editNotifications.MutedSet.ToList());

        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved.");
    }

    // ────────────────────────── Security ──────────────────────────

    private async Task UpdatePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _passwordError = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully.");
    }

    private async Task ToggleTwoFactor(ChangeEventArgs e)
    {
        var enabled = (bool)e.Value!;
        // Optimistically update the local state; a real app would call the service.
        _securitySettings = _securitySettings! with { TwoFactorEnabled = enabled };
        await ShowToast(enabled ? "Two-factor authentication enabled." : "Two-factor authentication disabled.");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // ────────────────────────── Appearance ──────────────────────────

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editAppearance!.Theme == "Dark") classes.Add("preview-dark");
        if (_editAppearance.FontSize == "Small") classes.Add("preview-small");
        if (_editAppearance.FontSize == "Large") classes.Add("preview-large");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(
            _editAppearance!.Theme,
            _editAppearance.FontSize,
            _editAppearance.Language,
            _editAppearance.CompactMode);

        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved.");
    }

    // ────────────────────────── Toast helper ──────────────────────────

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ────────────────────────── Helpers ──────────────────────────

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ────────────────────────── Edit models ──────────────────────────

    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio
        };
    }

    private class NotificationsEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public HashSet<string> MutedSet { get; set; } = [];
        public List<string> AllChannels { get; set; } = [];

        public static NotificationsEdit From(NotificationPrefs p) => new()
        {
            EmailNotifications = p.EmailNotifications,
            PushNotifications = p.PushNotifications,
            WeeklyDigest = p.WeeklyDigest,
            MutedSet = [..p.MutedChannels],
            AllChannels = [..p.MutedChannels]
        };
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode
        };
    }
}

/* ── Settings layout ── */

.settings-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav .nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    border-left: 3px solid transparent;
    transition: background 0.15s, border-color 0.15s;
}

.settings-nav .nav-item:hover {
    background: #e9ecef;
}

.settings-nav .nav-item.active {
    background: #e7f1ff;
    border-left-color: #0d6efd;
    color: #0d6efd;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content ── */

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 900px;
    position: relative;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* ── Toast ── */

.settings-toast {
    position: fixed;
    top: 1rem;
    right: 1rem;
    padding: 0.75rem 1.25rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    z-index: 1100;
    box-shadow: 0 4px 12px rgba(0,0,0,.15);
    animation: toast-slide-in 0.3s ease;
}

.toast-success {
    background: #198754;
    color: #fff;
}

.toast-error {
    background: #dc3545;
    color: #fff;
}

@keyframes toast-slide-in {
    from { opacity: 0; transform: translateY(-0.5rem); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Profile ── */

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

/* ── Toggle rows ── */

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #eee;
}

.toggle-row:last-child {
    border-bottom: none;
}

/* ── Channel list ── */

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    padding: 0.5rem 0;
}

/* ── Expandable password panel ── */

.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    user-select: none;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

/* ── Appearance preview ── */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    font-size: 0.9rem;
    transition: all 0.2s;
    background: #fff;
    color: #212529;
}

.preview-header {
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-btn {
    display: inline-block;
    padding: 0.35rem 0.75rem;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: #fff;
    border-radius: 0.3rem;
    cursor: default;
    font-size: inherit;
    margin-bottom: 0.75rem;
}

.preview-card {
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 0.35rem;
    padding: 0.75rem;
}

.preview-card p {
    margin: 0.25rem 0 0;
}

.preview-meta {
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    color: #6c757d;
    border-top: 1px solid #dee2e6;
}

/* Dark theme preview */
.appearance-preview.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-card {
    background: #313244;
    border-color: #45475a;
    color: #cdd6f4;
}

.preview-dark .preview-card a {
    color: #89b4fa;
}

.preview-dark .preview-meta {
    color: #a6adc8;
    border-color: #45475a;
}

.preview-dark .preview-btn {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

/* Font sizes */
.appearance-preview.preview-small {
    font-size: 0.8rem;
}

.appearance-preview.preview-large {
    font-size: 1.1rem;
}

/* Compact */
.appearance-preview.preview-compact .preview-header,
.appearance-preview.preview-compact .preview-body,
.appearance-preview.preview-compact .preview-meta {
    padding-top: 0.35rem;
    padding-bottom: 0.35rem;
}

.appearance-preview.preview-compact .preview-card {
    padding: 0.4rem;
}

/* ── Responsive ── */

@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding: 0.75rem 0;
    }

    .settings-nav {
        display: flex;
        overflow-x: auto;
    }

    .settings-nav .nav-item {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
    }

    .settings-nav .nav-item.active {
        border-left: none;
        border-bottom-color: #0d6efd;
    }

    .settings-content {
        padding: 1.5rem 1rem;
    }
}

toolCalls.args:
{"file_text": "@page "/settings"
@using sv_117e8ac5c8464b5aa11d4b2e2f54ec9c.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
