    </section>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Icon, string Label)> _sections = new()
    {
        ["profile"] = ("👤", "Profile"),
        ["notifications"] = ("🔔", "Notifications"),
        ["security"] = ("🔒", "Security"),
        ["appearance"] = ("🎨", "Appearance")
    };

    // ── Loading / Toast ──
    private bool _loading = true;
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile ──
    private ProfileEdit? _editProfile;
    private UserProfile? _savedProfile;

    // ── Notifications ──
    private NotificationsEdit? _editNotifications;

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "sess-1";

    // ── Appearance ──
    private AppearanceEdit? _editAppearance;

    // ────────────────────────── Lifecycle ──────────────────────────

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _savedProfile = profileTask.Result;
        _editProfile = ProfileEdit.From(_savedProfile);

        var notifs = notifTask.Result;
        _editNotifications = NotificationsEdit.From(notifs);

        _securitySettings = securityTask.Result;

        var appearance = appearanceTask.Result;
        _editAppearance = AppearanceEdit.From(appearance);

        _loading = false;
    }

    // ────────────────────────── Profile ──────────────────────────

    private async Task SaveProfile()
    {
        var profile = new UserProfile(
            _editProfile!.DisplayName,
            _editProfile.Email,
            _editProfile.AvatarUrl,
            _editProfile.Bio);

        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        _editProfile = ProfileEdit.From(_savedProfile!);
    }

    // ────────────────────────── Notifications ──────────────────────────

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editNotifications!.MutedSet.Add(channel);
        else
            _editNotifications!.MutedSet.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _editNotifications!.EmailNotifications,
            _editNotifications.PushNotifications,
            _editNotifications.WeeklyDigest,
            _editNotifications.MutedSet.ToList());

        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved.");
    }

    // ────────────────────────── Security ──────────────────────────

    private async Task UpdatePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _passwordError = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully.");
    }

    private async Task ToggleTwoFactor(ChangeEventArgs e)
    {
        var enabled = (bool)e.Value!;
        // Optimistically update the local state; a real app would call the service.
        _securitySettings = _securitySettings! with { TwoFactorEnabled = enabled };
        await ShowToast(enabled ? "Two-factor authentication enabled." : "Two-factor authentication disabled.");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // ────────────────────────── Appearance ──────────────────────────

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editAppearance!.Theme == "Dark") classes.Add("preview-dark");
        if (_editAppearance.FontSize == "Small") classes.Add("preview-small");
        if (_editAppearance.FontSize == "Large") classes.Add("preview-large");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(
            _editAppearance!.Theme,
            _editAppearance.FontSize,
            _editAppearance.Language,
            _editAppearance.CompactMode);

        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved.");
    }

    // ────────────────────────── Toast helper ──────────────────────────

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ────────────────────────── Helpers ──────────────────────────

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ────────────────────────── Edit models ──────────────────────────

    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio
        };
    }

    private class NotificationsEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public HashSet<string> MutedSet { get; set; } = [];
        public List<string> AllChannels { get; set; } = [];

        public static NotificationsEdit From(NotificationPrefs p) => new()
        {
            EmailNotifications = p.EmailNotifications,
            PushNotifications = p.PushNotifications,
            WeeklyDigest = p.WeeklyDigest,
            MutedSet = [..p.MutedChannels],
            AllChannels = [..p.MutedChannels]
        };
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode
        };
    }
}
