/* ── Settings layout ── */

.settings-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav .nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    border-left: 3px solid transparent;
    transition: background 0.15s, border-color 0.15s;
}

.settings-nav .nav-item:hover {
    background: #e9ecef;
}

.settings-nav .nav-item.active {
    background: #e7f1ff;
    border-left-color: #0d6efd;
    color: #0d6efd;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content ── */

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 900px;
    position: relative;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* ── Toast ── */

.settings-toast {
    position: fixed;
    top: 1rem;
    right: 1rem;
    padding: 0.75rem 1.25rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    z-index: 1100;
    box-shadow: 0 4px 12px rgba(0,0,0,.15);
    animation: toast-slide-in 0.3s ease;
}

.toast-success {
    background: #198754;
    color: #fff;
}

.toast-error {
    background: #dc3545;
    color: #fff;
}

@keyframes toast-slide-in {
    from { opacity: 0; transform: translateY(-0.5rem); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Profile ── */

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

/* ── Toggle rows ── */

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #eee;
}

.toggle-row:last-child {
    border-bottom: none;
}

/* ── Channel list ── */

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    padding: 0.5rem 0;
}

/* ── Expandable password panel ── */

.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    user-select: none;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

/* ── Appearance preview ── */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    font-size: 0.9rem;
    transition: all 0.2s;
    background: #fff;
    color: #212529;
}

.preview-header {
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-btn {
    display: inline-block;
    padding: 0.35rem 0.75rem;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: #fff;
    border-radius: 0.3rem;
    cursor: default;
    font-size: inherit;
    margin-bottom: 0.75rem;
}

.preview-card {
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 0.35rem;
    padding: 0.75rem;
}

.preview-card p {
    margin: 0.25rem 0 0;
}

.preview-meta {
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    color: #6c757d;
    border-top: 1px solid #dee2e6;
}

/* Dark theme preview */
.appearance-preview.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-card {
    background: #313244;
    border-color: #45475a;
    color: #cdd6f4;
}

.preview-dark .preview-card a {
    color: #89b4fa;
}

.preview-dark .preview-meta {
    color: #a6adc8;
    border-color: #45475a;
}

.preview-dark .preview-btn {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

/* Font sizes */
.appearance-preview.preview-small {
    font-size: 0.8rem;
}

.appearance-preview.preview-large {
    font-size: 1.1rem;
}

/* Compact */
.appearance-preview.preview-compact .preview-header,
.appearance-preview.preview-compact .preview-body,
.appearance-preview.preview-compact .preview-meta {
    padding-top: 0.35rem;
    padding-bottom: 0.35rem;
}

.appearance-preview.preview-compact .preview-card {
    padding: 0.4rem;
}

/* ── Responsive ── */

@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding: 0.75rem 0;
    }

    .settings-nav {
        display: flex;
        overflow-x: auto;
    }

    .settings-nav .nav-item {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
    }

    .settings-nav .nav-item.active {
        border-left: none;
        border-bottom-color: #0d6efd;
    }

    .settings-content {
        padding: 1.5rem 1rem;
    }
}

